class Solution {
    public int shipWithinDays(int[] weights, int days) {
        int sum = 0;
        int max = 0;
        for (int weight : weights) {
            sum += weight;
            if (weight > max) {
                max = weight;
            }
        }
        int left = max;
        int right = sum;
        while (left < right) {
            int mid = left + (right - left) / 2;
            if (isFeasible(mid, weights, days)) {
                right = mid;
            } else {
                left = mid + 1;
            }
        }
        return left;
    }

    private boolean isFeasible(int mid, int[] weights, int days) {
        int currentLoad = 0;
        int daysUsed = 0;
        for (int weight : weights) {
            if (currentLoad + weight > mid) {
                daysUsed++;
                currentLoad = weight;
            } else {
                currentLoad += weight;
            }
        }
        return daysUsed + 1 <= days;
    }
}

